mapper.select:

SELECT *
FROM 
	EXAM_PAPER
WHERE
	ENABLED_FLAG=1


AND ID=#{id}


AND EXAM_POLICY_ID=#{examPolicyId}


AND upper(PAPER_URL) like upper('%${paperUrl}%')


AND upper(GUID) like upper('%${guid}%')


AND upper(STATUS) like upper('%${status}%')


AND upper(USED) like upper('%${used}%')


AND UPDATE_DATE=#{updateDate}


AND UPDATED_BY=#{updatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}


AND ENABLED_FLAG=#{enabledFlag}


AND TIME=#{time}


AND TOTLE_SCORE=#{totleScore}


AND PASS_SCORE=#{passScore}

ORDER BY ID


SELECT 
	*
FROM 
	EXAM_PAPER,EXAM_SCOPE_POLICY_REL
WHERE
	ENABLED_FLAG=1


AND ID=#{bo.id}


AND EXAM_POLICY_ID=#{bo.examPolicyId}


AND upper(PAPER_URL) like upper('%${bo.paperUrl}%')


AND upper(GUID) like upper('%${bo.guid}%')


AND upper(STATUS) like upper('%${bo.status}%')


AND upper(USED) like upper('%${bo.used}%')


AND UPDATE_DATE=#{bo.updateDate}


AND UPDATED_BY=#{bo.updatedBy}


AND CREATION_DATE=#{bo.creationDate}


AND CREATED_BY=#{bo.createdBy}


AND ENABLED_FLAG=#{bo.enabledFlag}


AND TIME=#{bo.time}


AND TOTLE_SCORE=#{bo.totleScore}


AND PASS_SCORE=#{bo.passScore}


AND EXAM_SCOPE_POLICY_REL.POLICY_ID=EXAM_PAPER.EXAM_POLICY_ID
AND EXAM_SCOPE_POLICY_REL.SCOPE_ID=#{bo.scopeId}

ORDER BY ${page.sortFieldName} DESC
